// @ts-check
import { defineConfig } from 'astro/config';
import react from '@astrojs/react';

// wardline deploys to the ROOT of its own subdomain (IA §1.3, §1.4):
//   site:  https://wardline.foundryside.dev
//   base:  '/'   (each member site is a domain root — no subpath)
// Cross-subdomain links to siblings are ABSOLUTE https://{member}.foundryside.dev
// URLs generated by the shared @weft/site-kit data, so there is no base-path
// gymnastics and the hub and member sites cannot drift.
export default defineConfig({
  site: 'https://wardline.foundryside.dev',
  base: '/',
  integrations: [react()],
});
